import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { submitEventBooking } from "../utils/eventBookingApi";

const baseRates = {
  "Corporate Meeting": 18000,
  "Birthday Party": 22000,
  "Wedding Reception": 65000,
  "Private Dinner": 16000,
  "Family Celebration": 28000,
};

const EventBooking = () => {
  const navigate = useNavigate();
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [event_date, setEvent_date] = useState("");
  const [event_type, setEvent_type] = useState("Corporate Meeting");
  const [guests, setGuests] = useState("");

  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState("");
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");
    setSuccess("");

    try {
      const guestCount = Number(guests) || 0;
      const estimatedPrice = (baseRates[event_type] || 15000) + guestCount * 850;
      const payload = {
        name,
        email,
        phone,
        event_date,
        event_type,
        guests: guestCount,
        message: `${event_type} booking request for ${guests} guest(s).`,
      };

      const response = await submitEventBooking(payload);

      setLoading(false);
      setSuccess(response.data.message || "Event request sent successfully.");

      navigate("/makepayment", {
        state: {
          checkoutItem: {
            title: `${event_type} Event Booking`,
            description: `Name: ${name} | Email: ${email} | Phone: ${phone} | Guests: ${guestCount} | Event Date: ${event_date}`,
            amount: estimatedPrice,
            type: "Event Booking",
            image:
              "https://images.unsplash.com/photo-1519167758481-83f550bb49b3?auto=format&fit=crop&w=1200&q=80",
          },
          paymentNotice: "Your event request was saved successfully. Complete payment below.",
        },
      });

      // reset fields
      setName("");
      setEmail("");
      setPhone("");
      setEvent_date("");
      setEvent_type("Corporate Meeting");
      setGuests("");

    } catch (err) {
      setLoading(false);
      if (!err.response || err.response?.status === 404) {
        const guestCount = Number(guests) || 0;
        const estimatedPrice = (baseRates[event_type] || 15000) + guestCount * 850;

        navigate("/makepayment", {
          state: {
            checkoutItem: {
              title: `${event_type} Event Booking`,
              description: `Name: ${name} | Email: ${email} | Phone: ${phone} | Guests: ${guestCount} | Event Date: ${event_date}`,
              amount: estimatedPrice,
              type: "Event Booking",
              image:
                "https://images.unsplash.com/photo-1519167758481-83f550bb49b3?auto=format&fit=crop&w=1200&q=80",
            },
            paymentNotice:
              "The event booking service is not reachable right now, but you can still continue with payment.",
          },
        });
        return;
      }

      setError(err.response?.data?.message || "Failed to send booking request");
      console.error(err);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        name="name"
        placeholder="Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
        required
      />

      <input
        name="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
      />

      <input
        name="phone"
        placeholder="Phone"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
        required
      />

      <input
        type="date"
        name="event_date"
        value={event_date}
        onChange={(e) => setEvent_date(e.target.value)}
        required
      />

      <input
        name="event_type"
        placeholder="Event Type"
        value={event_type}
        onChange={(e) => setEvent_type(e.target.value)}
        required
      />

      <input
        type="number"
        name="guests"
        placeholder="Guests"
        value={guests}
        onChange={(e) => setGuests(e.target.value)}
        required
      />

      <button type="submit">
        {loading ? "Sending..." : "Send Event Request"}
      </button>

      {success && <p style={{ color: "green" }}>{success}</p>}
      {error && <p style={{ color: "red" }}>{error}</p>}
    </form>
  );
};

export default EventBooking;
